// Verificar se o remetente é autorizado
const CHAT_ID_AUTORIZADO = 198613263;
const chatId = $input.first().json.message?.chat?.id;
const nome = $input.first().json.message?.from?.first_name || 'Desconhecido';

if (chatId === CHAT_ID_AUTORIZADO) {
  // Usuário autorizado — não fazer nada (outros workflows respondem)
  return [];
} else {
  // Não autorizado — enviar aviso e bloquear
  return [{ json: { chat_id: chatId, nome } }];
}
